mapper.select:
SELECT sa.* FROM system_assessment sa
INNER JOIN customer_system cs ON sa.system_id = cs.id
WHERE sa.deleted = 0
  AND cs.deleted = 0

    AND cs.system_name LIKE CONCAT('%', #{systemName}, '%')


    AND cs.project_id = #{projectId}


    AND sa.review_status = #{reviewStatus}


    AND sa.priority_level = #{priorityLevel}

ORDER BY sa.total_score DESC, sa.assessment_date DESC

mapper.update:
UPDATE system_assessment SET review_status = #{reviewStatus}, reviewer_id = #{reviewerId}, review_date = CURDATE(), updated_at = NOW() WHERE id IN
#{id}
AND deleted = 0
